      "chapter_name": "Unit 1. Accounting for Partnership Firms",
      "topic": "Foundations of Accounting and Theoretical Framework",
      "outcomes": [
        "Explain the concept, objectives, and limitations of accounting along with its role in business."
      ]
    },
    {
      "unit_name": "Unit 2. Accounting for Companies",
      "chapter_name": "Unit 2. Accounting for Companies",
      "topic": "Accounting Process and Transaction Recording",
      "outcomes": [
        "Record accounting transactions accurately using the double entry system including journals, cash books, ledgers, and depreciation calculations."
      ]
    },
    {
      "unit_name": "Unit 3. Analysis of Financial Statements",
      "chapter_name": "Unit 3. Analysis of Financial Statements",
      "topic": "Analysis of Financial Statements and Cash Flow",
      "outcomes": [
        "Interpret financial data through ratio analysis and prepare a statement of cash flows."
      ]
    },
    {
      "unit_name": "Computerised Accounting",
      "chapter_name": "Computerised Accounting",
      "topic": "Computerised Accounting Systems",
      "outcomes": [
        "Operate basic functions of accounting software to record transactions and generate financial statements."
      ]
    },
    {
      "unit_name": "Cash Flow Statement",
      "chapter_name": "Cash Flow Statement",
      "topic": "Cash Flow Statement Preparation and Analysis",
      "outcomes": [
        "Construct a Cash Flow Statement by classifying inflows and outflows from operating, investing, and financing activities."
      ]
    },
    {
      "unit_name": "Unit 4. Computerized Accounting",
      "chapter_name": "Unit 4. Computerized Accounting",
      "topic": "Fundamentals of Computerized Accounting Systems",
      "outcomes": [
        "Identify key differences between manual and computerized accounting systems regarding efficiency and accuracy.",
        "Explain the role of hardware and software requirements for implementing a successful computerized accounting solution.",
        "Analyze the impact of automation on data entry, processing speed, and error reduction in financial record-keeping."
      ]
    }
  ]
}
